function visualize_smoothing_results(T_raw, T_smooth)
    % VISUALIZE_SMOOTHING_RESULTS Displays two figures to compare raw and 
    % smoothed rigid body transformations:
    %   Fig 1: Trajectory of X, Y, Z rotation basis vectors on a unit sphere.
    %   Fig 2: X, Y, Z translation components plotted over time.
    %
    % Inputs:
    %   T_raw    - 4x4xn array of raw rigid body transformations
    %   T_smooth - 4x4xn array of smoothed rigid body transformations
    %
    % P.s. This function is generated by Gemini 3.1. Pro Preview (15/04/2026)

    num_frames = size(T_raw, 3);
    frames = 1:num_frames;

    %% ====================================================================
    %  1. DATA EXTRACTION
    %  ====================================================================
    
    % --- Rotation Data (Columns 1, 2, 3) ---
    vx_raw = squeeze(T_raw(1:3, 1, :));
    vy_raw = squeeze(T_raw(1:3, 2, :));
    vz_raw = squeeze(T_raw(1:3, 3, :));

    vx_smooth = squeeze(T_smooth(1:3, 1, :));
    vy_smooth = squeeze(T_smooth(1:3, 2, :));
    vz_smooth = squeeze(T_smooth(1:3, 3, :));

    % --- Translation Data (Column 4) ---
    px_raw = squeeze(T_raw(1, 4, :));
    py_raw = squeeze(T_raw(2, 4, :));
    pz_raw = squeeze(T_raw(3, 4, :));

    px_smooth = squeeze(T_smooth(1, 4, :));
    py_smooth = squeeze(T_smooth(2, 4, :));
    pz_smooth = squeeze(T_smooth(3, 4, :));


    %% ====================================================================
    %  2. FIGURE 1: SPHERICAL ROTATION VISUALIZATION
    %  ====================================================================
    fig1 = figure('Name', 'Spherical Rotation Visualization (X,Y,Z)', 'Color', 'w');
    ax_rot = axes('Parent', fig1);
    hold(ax_rot, 'on');
    axis(ax_rot, 'equal');
    view(ax_rot, 3);
    grid(ax_rot, 'on');
    xlabel(ax_rot, 'World X'); ylabel(ax_rot, 'World Y'); zlabel(ax_rot, 'World Z');
    title(ax_rot, 'Local X (Red), Y (Green), Z (Blue) Axes Trajectories on Sphere');

    % Plot a faint, semi-transparent unit sphere
    [sx, sy, sz] = sphere(40);
    surf(ax_rot, sx, sy, sz, 'FaceColor',[0.9 0.9 0.95], 'EdgeColor', 'none', ...
         'FaceAlpha', 0.5, 'HandleVisibility', 'off'); 
    camlight(ax_rot, 'headlight');
    lighting(ax_rot, 'gouraud');

    % Prepare the error connections using the NaN-separator trick
    nan_row = nan(1, num_frames);
    
    cx_x =[vx_raw(1, :); vx_smooth(1, :); nan_row];
    cx_y =[vx_raw(2, :); vx_smooth(2, :); nan_row];
    cx_z =[vx_raw(3, :); vx_smooth(3, :); nan_row];

    cy_x =[vy_raw(1, :); vy_smooth(1, :); nan_row];
    cy_y =[vy_raw(2, :); vy_smooth(2, :); nan_row];
    cy_z =[vy_raw(3, :); vy_smooth(3, :); nan_row];

    cz_x =[vz_raw(1, :); vz_smooth(1, :); nan_row];
    cz_y =[vz_raw(2, :); vz_smooth(2, :); nan_row];
    cz_z =[vz_raw(3, :); vz_smooth(3, :); nan_row];

    % Plot the error connections (faint colors, hidden from legend)
    plot3(ax_rot, cx_x(:), cx_y(:), cx_z(:), 'Color', [1 0.8 0.8], 'LineWidth', 0.5, 'HandleVisibility', 'off');
    plot3(ax_rot, cy_x(:), cy_y(:), cy_z(:), 'Color',[0.8 1 0.8], 'LineWidth', 0.5, 'HandleVisibility', 'off');
    plot3(ax_rot, cz_x(:), cz_y(:), cz_z(:), 'Color',[0.8 0.8 1], 'LineWidth', 0.5, 'HandleVisibility', 'off');

    % Plot the RAW trajectories (thin lines, light colors)
    plot3(ax_rot, vx_raw(1,:), vx_raw(2,:), vx_raw(3,:), 'Color',[1 0.5 0.5], ...
          'LineWidth', 1, 'DisplayName', 'Raw X');
    plot3(ax_rot, vy_raw(1,:), vy_raw(2,:), vy_raw(3,:), 'Color',[0.5 1 0.5], ...
          'LineWidth', 1, 'DisplayName', 'Raw Y');
    plot3(ax_rot, vz_raw(1,:), vz_raw(2,:), vz_raw(3,:), 'Color',[0.5 0.5 1], ...
          'LineWidth', 1, 'DisplayName', 'Raw Z');

    % Plot the SMOOTHED trajectories (thick lines, bold colors)
    plot3(ax_rot, vx_smooth(1,:), vx_smooth(2,:), vx_smooth(3,:), 'Color', [0.8 0 0], ...
          'LineWidth', 2.5, 'DisplayName', 'Smoothed X');
    plot3(ax_rot, vy_smooth(1,:), vy_smooth(2,:), vy_smooth(3,:), 'Color',[0 0.8 0], ...
          'LineWidth', 2.5, 'DisplayName', 'Smoothed Y');
    plot3(ax_rot, vz_smooth(1,:), vz_smooth(2,:), vz_smooth(3,:), 'Color', [0 0 0.8], ...
          'LineWidth', 2.5, 'DisplayName', 'Smoothed Z');

    legend(ax_rot, 'Location', 'bestoutside');
    xlim(ax_rot, [-1.1 1.1]); ylim(ax_rot,[-1.1 1.1]); zlim(ax_rot, [-1.1 1.1]);


    %% ====================================================================
    %  3. FIGURE 2: TRANSLATION VISUALIZATION (X, Y, Z)
    %  ====================================================================
    fig2 = figure('Name', 'Translation Visualization (X,Y,Z)', 'Color', 'w');
    
    % --- Subplot 1: X Translation ---
    ax_x = subplot(3, 1, 1, 'Parent', fig2);
    hold(ax_x, 'on'); grid(ax_x, 'on');
    % Raw uses solid line, smoothed uses dashed line
    plot(ax_x, frames, px_raw(:), 'r-', 'LineWidth', 1, 'DisplayName', 'Raw X');
    plot(ax_x, frames, px_smooth(:), 'r--', 'LineWidth', 2, 'DisplayName', 'Smoothed X');
    ylabel(ax_x, 'X Translation');
    title(ax_x, 'Translational Trajectories over Time');
    legend(ax_x, 'Location', 'best');

    % --- Subplot 2: Y Translation ---
    ax_y = subplot(3, 1, 2, 'Parent', fig2);
    hold(ax_y, 'on'); grid(ax_y, 'on');
    % Dark green ([0 0.7 0]) is used instead of pure 'g' for better visibility on white background
    plot(ax_y, frames, py_raw(:), '-', 'Color', [0 0.7 0], 'LineWidth', 1, 'DisplayName', 'Raw Y');
    plot(ax_y, frames, py_smooth(:), '--', 'Color', [0 0.7 0], 'LineWidth', 2, 'DisplayName', 'Smoothed Y');
    ylabel(ax_y, 'Y Translation');
    legend(ax_y, 'Location', 'best');

    % --- Subplot 3: Z Translation ---
    ax_z = subplot(3, 1, 3, 'Parent', fig2);
    hold(ax_z, 'on'); grid(ax_z, 'on');
    plot(ax_z, frames, pz_raw(:), 'b-', 'LineWidth', 1, 'DisplayName', 'Raw Z');
    plot(ax_z, frames, pz_smooth(:), 'b--', 'LineWidth', 2, 'DisplayName', 'Smoothed Z');
    ylabel(ax_z, 'Z Translation');
    xlabel(ax_z, 'Frame / Time Step');
    legend(ax_z, 'Location', 'best');

    % Link the X-axes of the translation plots so panning/zooming applies to all simultaneously
    linkaxes([ax_x, ax_y, ax_z], 'x');
    xlim(ax_x, [1, num_frames]);
end